INSERT INTO `social_media` (`id`, `platform`, `url`, `embed_code`, `title`, `description`, `thumbnail`, `created_at`, `updated_at`) VALUES
	(1, 'facebook', 'https://www.facebook.com/reel/1047611906895706', NULL, 'Nulla excepturi vel dolores suscipit.', 'Facilis ea laborum saepe non sint nemo. Alias voluptatem aut omnis molestiae. Minus ut et pariatur id omnis eligendi non error. Voluptatum accusamus consequatur vel repudiandae et dignissimos. Eum velit non est adipisci.', NULL, '2025-09-08 22:51:02', '2025-09-11 04:18:12'),
	(2, 'youtube', 'http://www.lang.com/', 'Ex vel quidem sed aut distinctio aspernatur. Voluptate pariatur ut consequuntur unde qui vel voluptates. Molestiae libero enim quia cumque culpa quia culpa.', 'Fugit ut totam voluptas impedit ut consequatur.', 'Porro impedit mollitia perspiciatis consectetur. Temporibus amet nesciunt architecto eos. Harum eos rerum architecto dolores quis. Ducimus vel illum quia commodi ratione et doloribus enim.', 'https://via.placeholder.com/640x480.png/009944?text=quia', '2025-09-08 22:51:02', '2025-09-08 22:51:02'),
	(3, 'facebook', 'https://www.facebook.com/reel/695765789872558', NULL, 'Molestiae ex debitis deleniti est saepe et laborum.', 'Molestias sapiente laudantium dignissimos consequatur recusandae. Tenetur totam maiores cum.', NULL, '2025-09-08 22:51:02', '2025-09-11 06:31:14'),
	(5, 'instagram', 'https://www.instagram.com/p/DOS_YEEk5u6/', 'Nihil odit autem vel quis dicta. Voluptatibus et iure qui consequatur ea veniam dignissimos ea. Temporibus maiores est velit nostrum autem dolor. Aut quis necessitatibus qui nihil veritatis.', 'Et sunt aliquam quis.', 'Necessitatibus illo tempora consectetur ipsa nesciunt ad. Voluptatem aut explicabo quis nisi aliquid. Ut sint et sit eos. Ipsa similique consequatur et quos tempora et voluptates.', NULL, '2025-09-08 22:51:02', '2025-09-11 05:56:09'),
	(6, 'tiktok', 'https://www.tiktok.com/@laodedarwin_official/video/7537547030210678024', 'Omnis tempore tempore quia nihil minus accusantium quae. Doloremque explicabo deleniti id. Consequatur qui praesentium temporibus laborum. Cumque voluptatem id possimus et.', 'Lomba Memancing 2025', 'Ikan besar selalu terlepas #mancingmania #lombamancing #munabarat #liwumokesa #sultra #pulauindo', NULL, '2025-09-08 22:51:02', '2025-09-11 04:24:13'),
	(7, 'instagram', 'https://www.instagram.com/p/DNiHXeQz_dg/', NULL, 'Bantuan pertanian dan peternakan kepada masyarakat', 'Tepat di momen peringatan hari ulang tahun (HUT) ke-80 kemerdekan RI, kami Pemerintah Kabupaten Muna Barat menyerahkan bantuan pertanian dan peternakan kepada masyarakat.', NULL, '2025-09-08 22:51:02', '2025-09-11 06:26:38'),
